typescript_example.code:
// Call the SAK race-server /evaluate endpoint from any TypeScript app
interface EvaluateRequest {
  slippage_bps: number;
  amount_lamports: number;
  program_ids: string[];
  compute_units?: number;
  description?: string;
}

interface EvaluateResponse {
  decision: 'allowed' | 'rejected';
  rule: string | null;
  reason: string | null;
  attack_type: string;
  severity: 'critical' | 'high' | 'medium' | 'low' | 'none';
  simulation_time_ms: number;
}

async function evaluate(
  intent: EvaluateRequest,
  serverUrl = 'http://localhost:3001'
): Promise<EvaluateResponse> {
  const res = await fetch(`${serverUrl}/evaluate`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(intent),
  });
  if (!res.ok) {
    const err = await res.json();
    throw new Error(`Guardian error: ${err.message}`);
  }
  return res.json();
}

// Example: test a suspicious intent
const result = await evaluate({
  slippage_bps: 9900,
  amount_lamports: 5_000_000_000, // 5 SOL
  program_ids: ['JUP6LkbZbjS1jKKwapdHNy74zcZ3tLUZoi5QNyVTaV4'],
  description: 'maximize swap output',
});

console.log(result.decision === 'rejected'
  ? `Blocked by ${result.rule}: ${result.reason}`
  : 'Transaction allowed');

